// RemoveTarget relationship.
// Sets o.R.Target to nil.
// Removes o from all passed in related items' relationships struct.
func (o *DryrunResult) RemoveTarget(ctx context.Context, exec boil.ContextExecutor, related *CrawlTarget) error {
	var err error

	queries.SetScanner(&o.TargetID, nil)
	if _, err = o.Update(ctx, exec, boil.Whitelist("target_id")); err != nil {
		return errors.Wrap(err, "failed to update local table")
	}

	if o.R != nil {
		o.R.Target = nil
	}
	if related == nil || related.R == nil {
		return nil
	}

	for i, ri := range related.R.TargetDryrunResults {
		if queries.Equal(o.TargetID, ri.TargetID) {
			continue
		}

		ln := len(related.R.TargetDryrunResults)
		if ln > 1 && i < ln-1 {
			related.R.TargetDryrunResults[i] = related.R.TargetDryrunResults[ln-1]
		}
		related.R.TargetDryrunResults = related.R.TargetDryrunResults[:ln-1]
		break
	}
	return nil
}

